92:   /**
93:    * Creates an equivalent {@code FxVanillaOption} using currency pair, option expiry, call/put flag, strike, base
94:    * currency notional, and underlying payment date.
95:    * <p>
96:    * No payment date adjustments apply.
97:    *
98:    * @param longShort the long/short flag of the option
99:    * @param expiry the option expiry
100:    * @param currencyPair the FX currency pair
101:    * @param putCall the put/call flag of the option
102:    * @param strike the FX strike
103:    * @param baseNotional the base currency notional amount: should always be positive
104:    * @param paymentDate the payment date of the underlying FX cash flows
105:    * @return an equivalent fx vanilla option
106:    */
107:   public static FxVanillaOption of(
108:       LongShort longShort,
109:       ZonedDateTime expiry,
110:       CurrencyPair currencyPair,
111:       PutCall putCall,
112:       double strike,
113:       double baseNotional,
114:       LocalDate paymentDate) {
115: 
116:     return of(longShort, expiry, currencyPair, putCall, strike, baseNotional, paymentDate, null);
117:   }
